Sure! Below is an example code for a Discord bot using Discord.js v14 that includes a single slash command called `ban`. This command will allow users with the appropriate permissions to ban another user from the server.

First, you need to install the necessary packages. Ensure you have `discord.js` and `@discordjs/rest` installed:

```bash
npm install discord.js @discordjs/rest
```

Next, create a file for your bot, say `index.js`, and add the following code:

```javascript
const { Client, GatewayIntentBits, REST, Routes } = require('discord.js');
const { token, clientId, guildId } = require('./config.json');

const client = new Client({ intents: [GatewayIntentBits.Guilds, GatewayIntentBits.GuildMessages, GatewayIntentBits.GuildMembers] });

client.once('ready', () => {
    console.log(`Logged in as ${client.user.tag}!`);
});

client.on('interactionCreate', async (interaction) => {
    if (!interaction.isCommand()) return;

    const { commandName, options } = interaction;

    if (commandName === 'ban') {
        const user = options.getUser('user');
        const member = interaction.guild.members.resolve(user);

        if (member) {
            await member.ban();
            await interaction.reply(`${user.tag} has been banned.`);
        } else {
            await interaction.reply('That user is not in the server.');
        }
    }
});

const commands = [
    {
        name: 'ban',
        description: 'Ban a user from the server.',
        options: [
            {
                type: 6, // TYPE 6 is for USER
                name: 'user',
                description: 'The user to ban',
                required: true
            }
        ]
    }
];

const rest = new REST({ version: '10' }).setToken(token);

(async () => {
    try {
        console.log('Started refreshing application (/) commands.');

        await rest.put(
            Routes.applicationGuildCommands(clientId, guildId),
            { body: commands },
        );

        console.log('Successfully reloaded application (/) commands.');
    } catch (error) {
        console.error(error);
    }
})();

client.login(token);
```

Create a `config.json` file to store your bot token and guild ID:

```json
{
    "token": "YOUR_BOT_TOKEN",
    "clientId": "YOUR_CLIENT_ID",
    "guildId": "YOUR_GUILD_ID"
}
```

Replace the placeholders in `config.json` with your actual bot token, client ID, and guild ID.

Start your bot with:

```bash
node index.js
```

This bot will now listen for the `/ban` command and allow users with the appropriate permissions to ban another user from the server.

Here's an example of a C++ function that takes a reference to a std::string containing markdown formatted text and returns a std::string containing html formatted text:

```
#include <iostream>
#include <string>
#include <regex>

std::string markdownToHtml(const std::string& markdown) {
  std::string html = markdown;

  // Headers
  std::regex h1_regex("^(#) (.+)$");
  html = std::regex_replace(html, h1_regex, "<h1>$2</h1>");
  std::regex h2_regex("^(##) (.+)$");
  html = std::regex_replace(html, h2_regex, "<h2>$2</h2>");
  std::regex h3_regex("^(###) (.+)$");
  html = std::regex_replace(html, h3_regex, "<h3>$2</h3>");
  std::regex h4_regex("^(####) (.+)$");
  html = std::regex_replace(html, h4_regex, "<h4>$2</h4>");
  std::regex h5_regex("^(#####) (.+)$");
  html = std::regex_replace(html, h5_regex, "<h5>$2</h5>");
  std::regex h6_regex("^(######) (.+)$");
  html = std::regex_replace(html, h6_regex, "<h6>$2</h6>");

  // Bold
  std::regex bold_regex("\\*\\*(.+?)\\*\\*");
  html = std::regex_replace(html, bold_regex, "<strong>$1</strong>");

  // Italic
  std::regex italic_regex("\\*(.+?)\\*");
  html = std::regex_replace(html, italic_regex, "<em>$1</em>");

  // Links
  std::regex link_regex("\\[(.+?)\\]\\((.+?)\\)");
  html = std::regex_replace(html, link_regex, "<a href=\"$2\">$1</a>");

  // Blockquotes
  std::regex blockquote_regex("> (.+)");
  html = std::regex_replace(html, blockquote_regex, "<blockquote>$1</blockquote>");

  // Code blocks
  std::regex codeblock_regex("```(.+?)```");
  html = std::regex_replace(html, codeblock_regex, "<pre><code>$1</code></pre>");

  // Inline code
  std::regex inlinecode_regex("`(.+?)`");
  html = std::regex_replace(html, inlinecode_regex, "<code>$1</code>");

  // Unordered lists
  std::regex ul_regex("^\\* (.+)$");
  html = std::regex_replace(html, ul_regex, "<li>$1</li>");
  html = std::regex_replace(html, "<li>(.+)</li>", "<ul><li>$1</li></ul>");

  // Ordered lists
  std::regex ol_regex("^\\d+\\. (.+)$");
  html = std::regex_replace(html, ol_regex, "<li>$1</li>");
  html = std::regex_replace(html, "<li>(.+)</li>", "<ol><li>$1</li></ol>");

  return html;
}
``` 

This function uses regular expressions to replace markdown syntax with the corresponding HTML tags. It supports headers, bold, italic, links, blockquotes, code blocks, inline code, unordered lists, and ordered lists. Note that this function may not cover all possible markdown syntax, and may need to be adjusted for specific use cases.

